		function RegShow()
{         	                                                 
	var modo = 'SHOW'; 

	if(Ctrl('portal').GetXValue() == "si")
		appendFormInMain("NucleusRH.Base.Evaluacion2.Evaluacion.EVALUACION.flow", 'PORTAL', '<DATA oi_evaluacion="'+Ctrl("LIST").GetXValue().split("_")[0] +'" modo="'+modo+'" CAMBIO_ESTADO="" portal="si"/>');
	else
		appendFormInMain("NucleusRH.Base.Evaluacion2.Evaluacion.EVALUACION.flow", 'EDIT_SHOW', '<DATA oi_evaluacion="'+Ctrl("LIST").GetXValue().split("_")[0] +'" modo="'+modo+'" CAMBIO_ESTADO="" editable="0" />');

	return true;
}              

function RegShowRol()
{         	                                                 
	var modo = ''; 
	switch(Ctrl("LIST").GetSelectAttrValue("ROL")){ 
	case 'Evaluador':
	 	modo = 'EVALUADOR';
	 	break; 
	case 'Autoevaluación':
		modo = 'EVALUADO';
		break; 
	case 'Supervisor':
		modo = 'SUPERVISOR';
		break;
	default:
		modo = 'EVALUADOR360';
			break; 

	}

	if(Ctrl('portal').GetXValue() == "si")
		appendFormInMain("NucleusRH.Base.Evaluacion2.Evaluacion.EVALUACION.flow", 'PORTAL', '<DATA oi_evaluacion="'+Ctrl("LIST").GetXValue().split("_")[0] +'" modo="'+modo+'" CAMBIO_ESTADO="" portal="si"/>');
	else
		appendFormInMain("NucleusRH.Base.Evaluacion2.Evaluacion.EVALUACION.flow", 'NOEDIT', '<DATA oi_evaluacion="'+Ctrl("LIST").GetXValue().split("_")[0] +'" modo="'+modo+'" CAMBIO_ESTADO="" editable="0" />');

	return true;
}          


function CheckEnabledViewButton()
{    
	//Verifica si debe o no habilitarse el boton (Ver Evaluacion)

	var result = false;  
	var state = Ctrl("LIST").GetSelectAttrValue("ESTADO");

  if (state == 'Cerrada') result = true;

	return result;	
}

//Habilita los Botones
function EnabledButtons()
{  
  var cur,f;
  if (Ctrl("LIST").GetXValue()=="" || Ctrl("LIST").TotalRow<=0)
  {  
    CtrlEnabled("VIEW"  ,false);     
   	CtrlEnabled("SHOWROL",false);

    CtrlEnabled("SHOW"  ,false);
    CtrlEnabled("ACCEPT",false);
    CtrlEnabled("ADD"   ,CheckEnabledButton("ADD"));
    CtrlEnabled("EDIT"  ,false);
    CtrlEnabled("DELETE",false);
    CtrlEnabled("ADMIN" ,false);

    //Buscar que botones estan habilitados siempre
    for (cur=CHLCFG.FirstChild(); cur; cur=cur.Next())
    {
      f=cur.GetAttrInt("flag");
      CtrlEnabled(cur.GetAttr("name"), (f==2?CheckEnabledButton(cur.GetAttr("name")):false));
    }
  } else
  if (Ctrl("LIST").GetSelectAttrValue("lock")!="")
  {
    CtrlEnabled("VIEW"  ,CheckEnabledViewButton());     
    CtrlEnabled("SHOWROL"  ,CheckEnabledButton("SHOWROL"));

    CtrlEnabled("SHOW"  ,CheckEnabledButton("SHOW"));
    CtrlEnabled("ACCEPT",CheckEnabledButton("ACCEPT"));
    CtrlEnabled("ADD"   ,CheckEnabledButton("ADD"));
    CtrlEnabled("EDIT"  ,Ctrl("LIST").GetSelectAttrValue("lock")=="2"?CheckEnabledButton("EDIT"):false);
    CtrlEnabled("DELETE",false);
    CtrlEnabled("ADMIN" ,(GetProxy().Admin()?CheckEnabledButton("ADMIN"):false));

    //Buscar que botones estan habilitados si esta bloqueado
    for (cur=CHLCFG.FirstChild(); cur; cur=cur.Next())
    {
      f=cur.GetAttrInt("flag");
      CtrlEnabled(cur.GetAttr("name"), (f==2?CheckEnabledButton(cur.GetAttr("name")):false));
    }
  } else
  {  
		CtrlEnabled("VIEW"  ,CheckEnabledViewButton());        
    CtrlEnabled("SHOWROL"  ,CheckEnabledButton("SHOWROL"));

    CtrlEnabled("SHOW"  ,CheckEnabledButton("SHOW"));
    CtrlEnabled("ACCEPT",CheckEnabledButton("ACCEPT"));
    CtrlEnabled("ADD"   ,CheckEnabledButton("ADD"));
    CtrlEnabled("EDIT"  ,CheckEnabledButton("EDIT"));
    CtrlEnabled("DELETE",CheckEnabledButton("DELETE"));
    CtrlEnabled("ADMIN" ,(GetProxy().Admin()?CheckEnabledButton("ADMIN"):false));

    //Habilitar todos los botones
    for (cur=CHLCFG.FirstChild(); cur; cur=cur.Next())
      CtrlEnabled(cur.GetAttr("name"), CheckEnabledButton(cur.GetAttr("name")));
  }
}
